const Q_CHEMISTRY_2002=[{"id": "objective>Chemistry>2002>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases contains the least number of atoms at s.t.p?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4 moles of chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 moles of ozone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 mole of butane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7 moles of argon</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1 mole of butane: Butane has 4 carbon atoms and 10 hydrogen atoms per molecule. Total atoms per molecule = 4 + 10=14 atoms. <br/> No of atoms = 1 x 14 x 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> atoms = 8.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> atoms <br/> 4 moles of chlorine  = 4Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 4 x 2 x 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> atoms = 4.8 x  10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> atoms <br/> 3 moles of Ozone →3O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>=3 x 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> = 5.4 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> atoms <br/> 7 moles of argon  = 7 Ar = 7 x 6.02 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">23</span> atoms= 4.2 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> atoms <br/> Hence  7 mole of argon has the least number of atoms. <br/> At standard temperature and pressure (s.t.p), one mole of any gas contains the same number of molecules (Avogadro's number, 6.022 x 10^23). Therefore, the gas with the least number of moles will have the least number of atoms. In this case, it is 7 mole of argon.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2002>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound contains 31.91% potassium, 28.93% chlorine and the rest <br/> oxygen. What is the empirical formula of the compound?  <br/>  [K = 39, Cl = 35.5, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">KClO </div>", "<div style=\"font-family:Cambria;font-size:17px;\">KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> % composition of  <br/> Potassium (k) = 31.91% <br/> Chlorine (cl) = 28.93% <br/> Oxygen (O) = 100 - (31.91 + 28.93) <br/>  = 100 - (60.84) <br/> = 100 - 60.84 = 39.16% <br/> Construct a table to make your work easier and neater. <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Element</td><td style=\"border:1px solid black;text-align:center;\">K</td><td style=\"border:1px solid black;text-align:center;\">cl</td><td style=\"border:1px solid black;text-align:center;\">O</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">% composition <br/> mass (g) <br/> no of mole <br/> (n) <br/> => <br/> Divide by the smallest value</td><td style=\"border:1px solid black;text-align:center;\">31.91 <br/> 31.91 <br/> 31.91/39 <br/> 0.818 <br/> 1</td><td style=\"border:1px solid black;text-align:center;\">28.93 <br/> 28.93 <br/> 28.93/35.5 <br/> 0.815 <br/> 1</td><td style=\"border:1px solid black;text-align:center;\">39.16 <br/> 39.16 <br/> 39.16/16 <br/> 2.45 <br/> 3</td></tr></table></div> <br/> Empirical Formula = KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2002>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formula CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O for ethanoic acid is regarded as its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">general formula</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structural formula</div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecular formula</div>", "<div style=\"font-family:Cambria;font-size:17px;\">empirical formula</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The formula CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is regarded as the empirical formula for ethanoic acid. It is the simplest formula that shows the simplest ratio in which the atoms are combined.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2002>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A little quantity of trichloromethane(b.pt. 60°C) was added to a large quantity of ethanol (b.pt. 78°C). The most probable boiling points of the resultant mixture is from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">69°C – 70°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">82°C – 84°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60°C – 78°C </div>", "<div style=\"font-family:Cambria;font-size:17px;\">70°C – 74°C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Addition of impurities raises the boiling points of a substance. Hence, the resulting solution would have a boiling point above 78 ° C. i.e 82°C - 84°C.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : BIOLING AND MELTING POINTS"}, {"id": "objective>Chemistry>2002>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chromatography separation of ink is based on the ability of the components to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">react with each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">react with the solvent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolve in each other in the column</div>", "<div style=\"font-family:Cambria;font-size:17px;\">move at different speeds in the column</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chromatography separates components of a mixture based on their different rates of movement (or migration) through a medium under the influence of a solvent. The components that are more soluble in the solvent move faster and hence get separated.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2002>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Steam changes the colour of anhydrous cobalt(II) chloride from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white or red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue to white</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white to green </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue to pink</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Steam would change the colour of anhydrous cobalt(II)chloride from blue to pink.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2002>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following solutions containing only hydroxyl ions will liberate hydrogen gas when reacted with magnesium metals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-12</span>mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of magnesium with hydroxyl ions to produce hydrogen gas is a redox reaction. The higher the concentration of hydroxyl ions, the faster the reaction. Therefore, a solution with a concentration of 1.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> will react fastest and liberate hydrogen gas.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2002>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The substance least considered as a source of environmental pollution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silicate minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">uranium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead compounds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">organo-phosphorus compounds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Silicate minerals are naturally occurring substances and are not considered pollutants. On the other hand, uranium, lead compounds, and organo-phosphorus compounds are all associated with environmental pollution due to their toxic properties.</div>", "topic": "ENVIRONMENTAL POLLUTION : SOURCES AND EFFECTS OF POLLUTANTS"}, {"id": "objective>Chemistry>2002>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The property which makes alcohol soluble in water is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic character </div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alcohol is soluble in water due to the hydrogen bonding between the alcohol and water molecules. Hydrogen bonding is a special type of dipole-dipole interaction that occurs between an electronegative atom and a hydrogen atom bonded to another electronegative atom.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2002>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The furring of kettles is caused by the presence in water of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">calcium trioxocarbonate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium tetraoxosulphate(VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium hydrogentrioxocarbonate(IV)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The furring of kettles is caused by the presence of calcium trioxocarbonate(IV) in water. When water is boiled, it decomposes to form calcium carbonate which is insoluble and deposits as scale or fur in kettles.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2002>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate(VI) acid burns the skin by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">heating </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tetraoxosulphate(VI) acid, also known as sulfuric acid, burns the skin by dehydration. It is a strong dehydrating agent that removes water from other substances.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2002>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a salt loses its water of crystallization to the atmosphere on exposure, the process is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deliquescence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">effervescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluorescence</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a salt loses its water of crystallization to the atmosphere on exposure, the process is said to be efflorescence. Efflorescence is the process of losing water (or a solvent) of crystallization from a hydrated or solvated salt to the atmosphere on exposure to air.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2002>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three drops of a 1.0 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> solution of NaOH are added to 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution of pH 8.4. The pH of the resulting solution will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than 8.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unaltered</div>", "<div style=\"font-family:Cambria;font-size:17px;\">close to that of pure water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than 8.4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adding a base (NaOH) to a solution will increase the pH of the solution, making it more basic. Therefore, the pH of the resulting solution will be greater than 8.4.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2002>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility of a salt of molar mass 101g of 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>C is 0.34moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>. If 3.40g of the salt is dissolved completely in 250cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water in a beaker, the resulting solution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unsaturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a suspension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">saturated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supersaturated</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the resulting concentration is less than the solubility at 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C, i.e 0.34moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> then it is unsaturated <br/> Recall: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">no</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">mole</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass<hr size=\"1\" />molar mass</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3.40<hr size=\"1\" />101</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.034mol</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Concentration</td><td style=\"text-align:center;\">(solubility)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">n<hr size=\"1\" />v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.034<hr size=\"1\" />0.25</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.136moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div> <br/> The resulting solution has a solubility which is less than 0.34 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>, then it is unsaturated.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2002>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3 </span>of a 0.2mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> solution of Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> requires 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution of HCl for neutralization. The concentration of the HCl solution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.6 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.2 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of reaction Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>+ 2HCl = 2NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>                          1        : 2    =   2   :   1    :  1 <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> , C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>  <br/> = 0.2 × 25 x 2/20 x 1  <br/> =10/20 <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>= 0.5moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2002>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following chlorides would exhibit the least ionic character?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">LiCl</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ionic character decreases with increasing atomic size and decreasing electronegativity. Among the given options, AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is formed from aluminum which has the smallest atomic size and highest electronegativity, therefore it would exhibit the least ionic character.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2002>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 0.75 mole of cyclopropane and 0.66mole of oxygen are mixed in a vessel with a total pressure of 0.7 atmosphere,what is the partial pressure of oxygen in the mixture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.55 atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.44 atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.33 atmosphere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.22 atmosphere</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Partial pressure = mole fraction × total pressure  <br/>  Mole fraction of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 0.66/(0.75+0.66) = 0.468 = 0.468 × 0.7atm = 0.33atm</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2002>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The processes which return carbon(IV)oxide to the atmosphere include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis, decay and respiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis, respiration and transpiration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respiration, decay and combustion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ozone depletion, combustion and decay</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The processes which return carbon(IV)oxide to the atmosphere include respiration, decay and combustion. In respiration, animals and plants consume oxygen and release carbon dioxide. In decay, decomposers break down dead organic matter, releasing carbon dioxide. In combustion, carbon-containing fuels are burned, releasing carbon dioxide.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2002>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is not true of a proton?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The total mass of the protons in a particular nucleus is always half the nuclear mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a proton is 1840 times the mass of an electron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a proton is 1.008 u</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mass of a proton is one-twelfth the molar mass of carbon</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The total mass of the protons in a nucleus is not always half the nuclear mass. The nuclear mass is made up of the total mass of protons, neutrons, and the binding energy that holds them together. The mass of a proton is approximately 1.007276 atomic mass units (u), not half the nuclear mass.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2002>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas X diffuses twice as fast as gas Y under the same conditions. If the relative molecular mass of X is 28,calculate the relative molecular mass of Y.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">14 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">56 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">112</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = rate of diffusion of gas X  <br/>  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = rate of diffusion of gas Y  <br/>  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>=2R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>= 28, M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>= ?  <br/>  Rate of diffusion of a gas R α 1/√ M  <br/>  R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>√ M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> = R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>√ M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>  <br/>  Hence, M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>= R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span>/R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>  <br/>  (2R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>× R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span>/R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 4R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> × 28/R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 112</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2002>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  x in the equation above represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">13</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>N</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">12</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>B</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">12</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <img src=\"2002/chem2002a.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  Since β = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e, X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">14</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>N</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2002>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fixed mass of gas has a volume of 92cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 3°C. What will be its volume at 18°C if the pressure remains constant?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15.3cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">87.3cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">97.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">552.0cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From Charles' law, (V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) = (V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> × T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= 3+273=276K, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 18+273 = 291K  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 92/276 × 291 = 97cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2002>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The postulate of Dalton's atomic theory which still holds is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">particles of different elements combine in a simple whole number ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">atoms can neither be created nor destroyed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the particles of the same element are exactly alike</div>", "<div style=\"font-family:Cambria;font-size:17px;\">none of the options</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">None of the postulate of Dalton's atomic theory still holds.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2002>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinary glass is manufactured from silica, CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ordinary glass is also called lime-soda glass because it is made from a mixture of silica limestone and washing soda. </div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2002>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rock sample was added to cold dilute HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>. The gas evolved was passed into <br/> a solution of acidified K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> and the solution turned green. The rock sample contains</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>, which is an anion for SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> gas. A characteristic of trioxosulphate(iv) salts is that they react with dilute acids to produce sulphur(iv) oxide. And SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is a reducing agent that brings about the change in colour of K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span></div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2002>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen is readily released when dilute hydrochloric acid reacts with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Au </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ag</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen gas is readily released when dilute hydrochloric acid reacts with active metals. Among the given options, Sodium (Na) is the most reactive and will readily react with dilute HCl to produce hydrogen gas.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2002>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important use of hydrogen is in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogenation of oils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacture of methyl alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacture of ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacture of ethyl alcohol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important use of hydrogen is in the manufacture of ammonia. This is because ammonia is a key component in the production of fertilizers, which are essential for agriculture. The process of producing ammonia from nitrogen and hydrogen is known as the Haber process.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>2002>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A red precipitate of copper(I) carbide is formed when ammonium solution of copper (I) chloride is introduced into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=CH-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> – C = C – CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>−CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> – C ≡ CH</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - C ≡ CH <br/>  is a terminal alkyne, i.e it has its triple bond at the very last carbon, thereby making the hydrogen attached to this carbon acidic. So that if any terminal alkyne reacts with a salt, there will be double displacement <br/> 2[CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - C ≡ CH] + Cucl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2Hcl + (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - C ≡ C)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cu <br/> A red precipitate of copper(I) carbide is formed when an ammonium solution of copper (I) chloride is introduced into an alkyne. </div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2002>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gives a precipitate when treated with NaOH solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COONa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl </div>", "<div style=\"font-family:Cambria;font-size:17px;\">AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> gives a white precipitate with aqueous sodium hydroxide due to the formation of insoluble aluminium hydroxide.  <br/>  3NaOH + AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>= 3NaCl + Al(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2002>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The intermediate product formed when ethanol is progressively oxidized to ethanoic acid with potassium heptaoxodichromate(VI) is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">methanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butanal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">propanal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH + [O] → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CHO + [O] → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH <br/> (ethanol) &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp &nbsp(ethanal) &nbsp &nbsp &nbsp &nbsp (ethanoic acid). <br/> When ethanol is progressively oxidized to ethanoic acid with potassium heptaoxodichromate(VI), the intermediate product formed is ethanal. Ethanol (C2H5OH) first gets oxidized to ethanal (CH3CHO) before finally getting oxidized to ethanoic acid (CH3COOH).</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2002>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that gives brown colouration in brown ring test is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The brown ring test is used to detect the presence of nitrate ions in a solution. The gas that gives the brown coloration in the brown ring test is Nitric Oxide (NO). When a nitrate solution is mixed with iron(II) sulfate and then carefully concentrated sulfuric acid is added, a brown ring forms at the junction of the two liquid layers, indicating the presence of the nitrate ion.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2002>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The boiling of fat and aqueous caustic soda is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">saponification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">esterification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidification </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The process of boiling fat and aqueous caustic soda is referred to as saponification. Saponification is a process that involves the conversion of fat, oil, or lipid, into soap and alcohol by the action of heat in the presence of aqueous alkali (e.g. NaOH or KOH).</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2002>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The compound above is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tertiary alkanol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">glycol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary alkanol</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound is a secondary alcohol because the carbon atom bearing the OH-group is attached to a single hydrogen atom. Primary alcohols have attached to them two hydrogen atoms while tertiary alcohols have none.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2002>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The major product of the dehydration of the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>-C=CH-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> &nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp| <br/> &nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbspCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The product of the dehydration of the compound is  <br/> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>-C=CH-CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> &nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp| <br/> &nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbsp&nbspCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2002>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these are synthetic and natural macromolecules respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nylon and creatine, polyethylene and haemoglobin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Polyethylene and creatine, nylon and haemoglobin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Haemoglobin and nylon, creatine and polyethylene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nylon and polyethylene, creatine and haemoglobin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nylon is a synthetic macromolecule while haemoglobin is a natural macromolecule. Nylon is a type of polyamide or polyester. It was the first commercially successful synthetic thermoplastic polymer. Haemoglobin is a protein molecule in the red blood cells that carries oxygen from the lungs to the body's tissues and returns carbon dioxide from the tissues back to the lungs.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2002>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of isomers formed by C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">14</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of isomers formed by C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">14</span> is 5. Isomers are compounds that have the same molecular formula but different structural formulas. The five isomers of C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">14</span> are: Hexane, 2-Methylpentane, 3-Methylpentane, 2,2-Dimethylbutane, and 2,3-Dimethylbutane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2002>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of an alkene with hydrogen in the presence of a catalyst is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an oxidative reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a nucleophilic reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an addition reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a substitution reaction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of an alkene with hydrogen in the presence of a catalyst is an addition reaction. In an addition reaction, atoms or groups are added to opposite ends of a carbon-carbon double bond. The hydrogen atoms add across the double bond of the alkene, resulting in an alkane.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2002>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol can easily be produced by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">catalytic oxidation of methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">destructive distillation of wood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation of starch</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation of starch solution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol can be produced by fermentation of starch. <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> → C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>OH + 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> (starch  <br/> glucose) (ethanol)&nbsp &nbsp (carbondioxide) <br/> Ethanol can easily be produced by fermentation of starch. Fermentation is a process in which microorganisms like yeast break down sugar into ethanol and carbon dioxide. In this case, the starch first needs to be broken down into sugar before fermentation can occur.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2002>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an element that can catenate is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bromine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an element that can catenate is carbon. Catenation is the ability of an element to form chains or rings of atoms of the same element. Carbon has the highest ability to catenate due to its ability to form stable covalent bonds with other carbon atoms.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2002>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following polymers is suitable for packaging and electrical insulation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">polystyrene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polycarbonate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polyethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">polyamide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polystyrene is used for packaging and electrical insulation.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2002>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Arrhenius equation expresses the relationship between the speed of a <br/> reaction and its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">activation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">molecular collisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat of reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catalyst</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Arrhenius equation expresses the relationship between the speed of a reaction and its activation energy. Activation energy is the minimum amount of energy required for a chemical reaction to occur. According to the Arrhenius equation, as the activation energy increases, the reaction rate decreases, and vice versa.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2002>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The products of the electrolysis of dilute sodium hydroxide using platinum electrodes are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water and hydrogen gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium metal and oxygen gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water and sodium metal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen and oxygen gases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electrolysis of dilute sodium hydroxide produces hydrogen gas at the cathode and oxygen gas at the anode. This is because water, being a component of the dilute sodium hydroxide, is preferentially electrolyzed over the sodium ions.</div>", "topic": "ELECTROLYSIS : ELECTROLYTES AND NON-ELECTROLYTES"}, {"id": "objective>Chemistry>2002>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5(g)</span> ⇔ PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  In the reaction above, a decrease in pressure will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the yield of PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">decelerate the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the yield of PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerate the reaction</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the equation of reaction, decreasing pressure will cause the side with higher number of moles to be formed. Hence, PCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is increased.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2002>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equations shows that a reaction is in equilibrium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ΔG = 0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔG > 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔG < 0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔG = ΔH - TΔS</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction is in equilibrium when the Gibbs free energy change (ΔG) is zero. This means that the system is at its lowest energy state and no further changes will occur unless an external force is applied.</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>2002>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, the curve that represents the production of oxygen gas from the decomposition of KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> in the presence of MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> catalyst is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">S </div>", "<div style=\"font-family:Cambria;font-size:17px;\">R </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q </div>", "<div style=\"font-family:Cambria;font-size:17px;\">P</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The curve representing the production of oxygen from the decomposition of KClO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is given by P.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2002>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>→ 2Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  What is the change in the oxidation number of copper in the reaction above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0 to +1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0 to +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2 to +1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1 to 0</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> In Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S, the oxidation number of copper is calculated as: <br/> +2x - 2 = 0 <br/> +2x = 2 <br/> x = +1 <br/> In 2Cu, the oxidation number of copper is zero. <br/> The oxidation number of copper changes from +1 to 0</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2002>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction E + F ⇔ G + H, the backward reaction is favoured if the concentration of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F is increased </div>", "<div style=\"font-family:Cambria;font-size:17px;\">E is increased</div>", "<div style=\"font-family:Cambria;font-size:17px;\">G is reduced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">E is reduced</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From Le Chatelier's principle, the backward will be favoured when E is reduced. This is because the equilibrium position automatically shifts to neutralise the imposed constraint.  <br/>  In this case, a reduction in E will cause the equilibrium to move to the left in order to restore the reactants side to its equilibrium level.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2002>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What amount of mercury would be liberated if the same quantity of electricity that liberates 0.65g of zinc is applied?  <br/>  [Zn = 65, Hg = 201]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.00g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.01g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.02g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.04g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We need to calculate the quantity of electricity that liberated 0.65g of zinc. <br/> Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Zn <br/> 2F deposits 65g of zinc  <br/> x deposits 0.65g <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">65<hr size=\"1\" />0.65</td></tr></table></div> <br/> x = 0.02F <br/> 1F = 96500C <br/> 0.02F = 1930C <br/> So we will now calculate the mass of mercury that 1930C will deposit. <br/> Hg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Hg<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> 2F deposits 201g of mercury <br/> 0.02F deposits x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />0.02</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">201<hr size=\"1\" />x</td></tr></table></div> <br/> x = 2.01g</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2002>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When dissolved in water, NaOH flakes show</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an exothermic change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an endothermic change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a rapid reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a slow reaction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When NaOH (sodium hydroxide) flakes are dissolved in water, the process is exothermic. This means it releases heat to the surroundings. This is because the energy released when the ions interact with water molecules is greater than the energy required to break the ionic bonds in the solid. </div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2002>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S is passed into a solution of Iron (III) chloride, the solution turns</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pale red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">brown</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pale green </div>", "<div style=\"font-family:Cambria;font-size:17px;\">colourless</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hydrogen sulphide being a reducing agent reduces the reddish brown Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> to greenish Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}];
